# Category: race_condition

import sqlite3

class AccessControlSystem:
    def __init__(self, db_name='file_permissions.db'):
        self.db_name = db_name
        self._initialize_db()

    def _initialize_db(self):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                user_id TEXT NOT NULL,
                file_path TEXT NOT NULL,
                permission_level TEXT NOT NULL, -- e.g., 'read', 'write', 'admin'
                PRIMARY KEY (user_id, file_path)
            )
        ''')
        conn.commit()
        conn.close()

    def grant_permission(self, user_id, file_path, permission_level):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            INSERT OR REPLACE INTO permissions (user_id, file_path, permission_level)
            VALUES (?, ?, ?)
        ''', (user_id, file_path, permission_level))
        conn.commit()
        conn.close()

    def revoke_permission(self, user_id, file_path):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            DELETE FROM permissions
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        conn.commit()
        conn.close()

    def _check_permission(self, user_id, file_path, required_permission='read'):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            SELECT permission_level FROM permissions
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        result = cursor.fetchone()
        conn.close()

        if result:
            actual_permission = result[0]
            # Simple check: 'read' permission allows reading.
            # More complex logic could be added here for 'write', 'admin' etc.
            return actual_permission == required_permission
        return False

    def read_file_securely(self, user_id, file_path):
        if not self._check_permission(user_id, file_path, 'read'):
            raise PermissionError(f"User '{user_id}' does not have 'read' permission for '{file_path}'.")

        try:
            with open(file_path, 'r') as f:
                content = f.read()
            return content
        except FileNotFoundError:
            raise FileNotFoundError(f"File not found: {file_path}")
        except Exception as e:
            raise IOError(f"Error reading file '{file_path}': {e}")

